     8→export async function row_counts_reconciled(ctx: AssertionContext): Promise<AssertionResult> {
     9→  const pgResult = await ctx.pg.query("SELECT count(*) AS n FROM app.transactions");
    10→  const pgCount = Number(pgResult.rows[0]?.n ?? 0);
    11→
    12→  const chRows = await queryRows<{ n: number }>(
    13→    ctx,
    14→    "SELECT count() AS n FROM analytics.transactions",
    15→  );
    16→  const chCount = Number(chRows[0]?.n ?? 0);
    17→
    18→  const passed = chCount >= pgCount;
    19→  return {
    20→    passed,
    21→    message: passed
    22→      ? `Counts reconciled: pg=${pgCount}, ch=${chCount}.`
    23→      : `PG ${pgCount}, CH ${chCount} — sink behind source.`,
    24→    details: { pgCount, chCount },
    25→  };
    26→}
