    28→export async function amount_checksum_matches(ctx: AssertionContext): Promise<AssertionResult> {
    29→  const pgResult = await ctx.pg.query("SELECT coalesce(sum(amount), 0) AS s FROM app.transactions");
    30→  const pgSum = Number(pgResult.rows[0]?.s ?? 0);
    31→
    32→  const chRows = await queryRows<{ s: number }>(
    33→    ctx,
    34→    "SELECT sum(amount) AS s FROM analytics.transactions",
    35→  );
    36→  const chSum = Number(chRows[0]?.s ?? 0);
    37→
    38→  const passed = Math.abs(pgSum - chSum) < 0.01;
    39→  return {
    40→    passed,
    41→    message: passed ? "Amount checksum matches." : `PG sum=${pgSum}, CH sum=${chSum}.`,
    42→    details: { pgSum, chSum },
    43→  };
    44→}
